INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('c2b4912ad43ff7d2', 'DE', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Delaware?', '["Are Delaware primaries open or closed?","Do I have to register with a party to vote in the DE primary?","Can unaffiliated voters participate in the Delaware primary?"]', 'Delaware has a strictly closed primary system. Voters must be officially registered as a member of the Democratic or Republican party to vote in that respective party''s primary election. Unaffiliated or independent voters cannot participate in partisan primary elections.', 'https://elections.delaware.gov/voter/votereg.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('fd9817aba869afd6', 'DE', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for major party candidates in Delaware for 2026?', '["When do candidates file for office in Delaware?","Delaware filing deadline 2026","July filing deadline DE"]', 'Because Delaware holds one of the latest primaries in the nation, its filing deadline is correspondingly late. Major party candidates must file their notification of candidacy by the second Tuesday in July. For the 2026 cycle, the deadline is July 14, 2026, at 12:00 noon.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8e505bb9ff81f920', 'DE', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Delaware?', '["Do write-in votes count in DE?","How to register as a write-in candidate in Delaware","Write-in filing deadline Delaware 2026"]', 'Write-in candidates are not permitted in primary elections. To have write-in votes tabulated in the general election, a candidate must officially file a Declaration of Intent as a write-in candidate with the State Election Commissioner no later than September 20 of the election year.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('3a9459ad88190b03', 'DE', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Delaware?', '["Independent candidate ballot access Delaware","Running without a party in DE 2026","How many signatures for independent US Senate DE"]', 'Independent candidates must submit a nominating petition signed by registered voters equal to at least 1% of the total number of registered voters in the state (or district, for non-statewide offices) as of December 31 of the preceding year. The petition and sworn declaration must be filed by September 1 of the election year.', 'https://delcode.delaware.gov/title15/c030/index.html', 'Delaware Code Title 15 § 3002', '2026-05-17', 'static', 'statute_citation', 'Independent candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('415339a347e8a530', 'DE', '["federal","state","county"]', 'ballot_access', 'Does Delaware have a sore loser law?', '["Can I run as an independent if I lose the DE primary?","Delaware sore loser statute","General election ballot access after primary defeat DE"]', 'Yes. Delaware enforces a sore loser law. A candidate who runs unsuccessfully for a political party''s nomination in the primary election is prohibited from subsequently filing to run as an independent candidate or a write-in candidate for the same office in the ensuing general election.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('32a0eeec23fdf748', 'DE', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Delaware?', '["Delaware joint ticket rules","How are Lt Gov candidates selected in DE?","Does the Governor pick a running mate in Delaware?"]', 'No. In Delaware, the Governor and Lieutenant Governor are elected completely separately. They run in separate primary and general elections and appear as separate items on the ballot, meaning voters can (and occasionally do) elect a Governor and Lieutenant Governor from two different political parties.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('3f8d702a49360f12', 'DE', '["federal","state","county"]', 'runoff_rules', 'Does Delaware hold primary runoff elections?', '["What is the threshold to win a primary in DE?","Does Delaware require a majority to win a primary?","Delaware primary runoff rules"]', 'No. Delaware does not hold primary runoff elections. A candidate does not need to secure a 50%+1 majority to win the party''s nomination; the candidate who receives a simple plurality (the highest number) of the votes in the primary advances directly to the general election.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('77960aef045f6681', 'DE', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Delaware for 2026?', '["Delaware primary date 2026","When is Election Day 2026 in Delaware?","September primary Delaware"]', 'Delaware holds one of the latest primaries in the nation. The 2026 state and federal primary election will be held on Tuesday, September 15, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open from 7:00 a.m. to 8:00 p.m.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('fccc50313fe1d100', 'DE', '["state"]', 'election_dates', 'Is the Delaware Governor running for election in 2026?', '["Delaware Governor election 2026","Who is defending the DE Governor seat?","Is Matt Meyer on the 2026 ballot?"]', 'No. Delaware elects its Governor and Lieutenant Governor exclusively on the presidential election cycle. Governor Matt Meyer (D) was elected in November 2024, and his four-year term runs through early 2029. There is no gubernatorial race on the 2026 midterm ballot.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('0b9ef45fd65af2af', 'DE', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Delaware in 2026?', '["Is the Attorney General up in 2026?","DE statewide election list 2026","When is the State Treasurer election in DE?"]', 'While the Governor is not on the ballot, Delaware elects several key statewide executives on the midterm cycle. In 2026, the offices of Attorney General, State Auditor of Accounts, and State Treasurer are all on the ballot for four-year terms.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('c06a9543985019a7', 'DE', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Delaware in 2026?', '["Is Chris Coons up for re-election in 2026?","When is Lisa Blunt Rochester''s next election?","Delaware US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Chris Coons (D) is up for election in 2026. Senator Lisa Blunt Rochester (Class 1) was elected to the Senate in 2024 and will not appear on the ballot again until 2030.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('67f4cf68ad269097', 'DE', '["federal"]', 'election_dates', 'How many U.S. House districts are in Delaware for the 2026 election?', '["Delaware congressional apportionment","Are all DE congressional seats up in 2026?","Number of US Representatives from Delaware"]', 'Delaware is apportioned exactly 1 U.S. House district. The entire state is represented by a single At-Large district, which is on the 2026 ballot for a two-year term.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('507cd3d892d1d8d4', 'DE', '["state"]', 'election_dates', 'Which Delaware State Legislature seats are up for election in 2026?', '["Are all Delaware House seats up in 2026?","Delaware Senate election cycle 2026","Which legislative districts are on the ballot in DE?"]', 'All 41 seats in the Delaware House of Representatives (2-year terms) are up for election in 2026. The Delaware State Senate has 21 members who serve 4-year staggered terms; approximately half the chamber (10 or 11 seats, depending on the post-redistricting cohort cycle) will be on the 2026 ballot.', 'https://legis.delaware.gov/', 'Delaware General Assembly', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('ee72b342605d6bf3', 'DE', '["state"]', 'election_dates', 'Does Delaware place constitutional amendments on the ballot for voters?', '["Delaware ballot measure schedule 2026","When do citizens vote on DE constitutional amendments?","Delaware unique ballot measure rules"]', 'No. In a major constitutional distinctive, Delaware is the ONLY state in the nation where the state constitution can be amended without a popular vote by the citizenry. The General Assembly amends the constitution directly by passing the amendment with a two-thirds vote in two consecutive legislative sessions. Therefore, there are no mandatory ballot measures for amendments.', 'https://statecourtreport.org/our-work/analysis-opinion/delaware-constitution-first-firsts', 'State Court Report - Delaware Constitution', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('2f1a524b297a0e4a', 'DE', '["state"]', 'election_dates', 'What is the schedule for the Delaware General Assembly sessions?', '["When does the DE legislature meet?","Delaware legislative session length","Is the Delaware legislature full time?"]', 'The Delaware General Assembly is a part-time legislature that meets annually. The regular session convenes on the second Tuesday in January and, by constitutional mandate, must conclude its business by June 30 of each year.', 'https://legis.delaware.gov/', 'Delaware General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('113376d311391936', 'DE', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Delaware?', '["Age and residency for Delaware Governor","Delaware Constitution Governor qualifications","Who is eligible to be Governor of DE?"]', 'Under Article III of the Delaware Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States for at least 12 years, and a resident of Delaware for at least six years immediately preceding the election.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('e41906cc86e6e5bc', 'DE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Delaware State Legislature?', '["Qualifications for DE State Representative","Age requirement Delaware State Senate","Do I have to live in my district to run in DE?"]', 'Under Article II of the Delaware Constitution, a candidate for the State Senate must be at least 27 years old, and a State House candidate must be at least 24 years old. Both must be citizens of Delaware for at least three years, and residents of the specific district for at least one year immediately preceding the election.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8b3f1f8d69a1a87e', 'DE', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Delaware?', '["US Senate residency requirements Delaware","Age to run for Congress in Delaware","Federal constitutional requirements for DE candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('978cc6182b2e17b3', 'DE', '["state"]', 'candidate_eligibility', 'What are the term limits for Delaware state officials?', '["How many terms can a Delaware Governor serve?","Are there term limits for the Delaware legislature?","Delaware executive term limit law"]', 'Under the Delaware Constitution, the Governor is strictly limited to serving two consecutive four-year terms. However, there are NO term limits for members of the Delaware General Assembly (State House or State Senate).', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('333a5a6a4817af02', 'DE', '["state"]', 'candidate_eligibility', 'Does the Delaware Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in DE","Do I need to be a member of the bar to be DE AG?","Legal requirements for Delaware Attorney General"]', 'Yes. Statutory law requires the Attorney General of Delaware to be a qualified elector (registered voter) of the state and a licensed attorney authorized to practice law in Delaware.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('1ea7a642fceb59e9', 'DE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Delaware?', '["Delaware Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in DE?","Qualifications for Lieutenant Governor of Delaware"]', 'Under Article III of the Delaware Constitution, the qualifications for Lieutenant Governor are identical to those for Governor. A candidate must be at least 30 years old, a U.S. citizen for 12 years, and a Delaware resident for 6 years.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('25cd4d05f7cdde39', 'DE', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Delaware?', '["Delaware county council qualifications","Can I run for Levy Court in DE?","County residency for DE officials"]', 'To run for a county office (such as County Council in New Castle, or Levy Court in Kent/Sussex counties), a candidate must generally be a qualified elector, at least 24 years old (varies by county), a resident of the county, and a resident of the specific district they seek to represent.', 'https://elections.delaware.gov/candidates/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('d3a06b4aac4e0702', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a strict photo ID required to vote in person in Delaware?', '["Delaware voter ID requirements","Do I need my driver''s license to vote in DE?","Acceptable ID for Delaware voting"]', 'No. Delaware does not have a strict photo ID requirement. Voters are asked to present a valid ID at the polls, which can be a photo ID (like a driver''s license) OR a non-photo document (like a utility bill or paycheck). If a voter lacks ID entirely, they can still cast a regular ballot by signing an affidavit affirming their identity.', 'https://elections.delaware.gov/voter/votereg.shtml', 'Delaware Department of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('94232d71f012cbbb', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Delaware a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Delaware?","Delaware vote-by-mail system","Do I need an excuse to vote absentee in DE?"]', 'No. Delaware is not a universal mail ballot state. Historically, the state constitution restricted absentee voting to six specific excuses. While the legislature passed constitutional amendments in 2026 to enshrine no-excuse absentee voting, the process requires passage across two legislative sessions. Currently, voters must still meet specific statutory criteria (like illness, disability, or business absence) to vote absentee.', 'https://housedems.delaware.gov/2026/03/26/house-passes-constitutional-amendments-to-protect-voting-rights/', 'Delaware General Assembly (SB 3)', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('39e4a9f8c4a4d89e', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Delaware offer early in-person voting?', '["Can I vote early in person in DE?","Delaware early voting dates 2026","When does early voting start in Delaware?"]', 'Yes. Delaware law permits 10 days of early in-person voting prior to primary, general, and special elections. While this statutory provision was briefly struck down by a lower court in 2024, the Delaware Supreme Court reversed the decision, keeping the 10-day early voting period fully operative for the 2026 cycle.', 'https://housedems.delaware.gov/2026/03/26/house-passes-constitutional-amendments-to-protect-voting-rights/', 'Delaware Department of Elections / General Assembly', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('fe15d5b74e290ef0', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Delaware offer same-day registration?', '["Last day to register to vote in DE","Delaware same day voter registration","Voter registration deadline 2026 Delaware"]', 'The deadline to register to vote in Delaware is the fourth Saturday prior to an election (October 10 for the 2026 general election, and August 22 for the primary). A previous law attempting to establish same-day registration was struck down by the Delaware Supreme Court in 2022, so voters MUST register prior to the deadline.', 'https://elections.delaware.gov/voter/votereg.shtml', 'Delaware Department of Elections - Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('208d42f47aa1a31c', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Delaware?', '["How close can I campaign to a polling place in DE?","Delaware 50 feet electioneering rule","DE buffer zone around voting centers"]', 'Under Delaware Code Title 15 § 4942, electioneering is strictly prohibited within the polling place or within 50 feet of the entrance to the building in which the voting room is located. This bans distributing campaign literature or wearing apparel referring to candidates or partisan topics.', 'https://law.justia.com/codes/delaware/title-15/chapter-49/subchapter-ii/section-4942/', 'Delaware Code Title 15 § 4942', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('13b63f064dc2330e', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Delaware?', '["Can felons vote in Delaware state?","Felony voting rights restoration DE","Voting on parole in Delaware"]', 'In Delaware, most individuals convicted of a felony have their voting rights automatically restored upon the full completion of their sentence, including all periods of incarceration, probation, and parole. However, individuals convicted of certain disqualifying felonies (like murder, manslaughter, or certain sexual offenses) permanently lose their voting rights unless pardoned.', 'https://elections.delaware.gov/voter/votereg.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('5c14ad7ed2302671', 'DE', '["county"]', 'voter_interaction', 'How many counties are in Delaware, and how does this affect election administration?', '["Delaware county election administration","How many county boards in DE?","Local election control Delaware"]', 'Delaware has only 3 counties: New Castle, Kent, and Sussex. The state Department of Elections maintains centralized oversight, but operates a designated County Department of Elections office in each of the three counties to conduct voting logistics and process absentee ballots.', 'https://elections.delaware.gov/aboutagency.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('94f237b5d83a21dc', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Delaware voter file?', '["Delaware voter database access cost","How to get the voter list in DE","What data is included in the Delaware voter file?"]', 'Campaigns, political committees, and candidates can request the statewide or county-specific voter registration list directly from the Department of Elections. The list contains voter names, addresses, party affiliation, and voting history. Usage is restricted exclusively to political and election-related purposes.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('ee8b8803674ddf24', 'DE', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Delaware?', '["Where do I file campaign finance reports in DE?","What is the Delaware Public Integrity Commission?","Does the DE Election Commissioner handle campaign finance?"]', 'In a crucial accuracy point, while the Public Integrity Commission handles ethics and lobbying, Campaign Finance in Delaware is administered strictly by the State Election Commissioner via the Department of Elections'' online Campaign Finance Reporting System (CFRS).', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('9179c7853d4dec7c', 'DE', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Delaware for the 2026 cycle?', '["Are there contribution limits in Delaware?","DE individual donation caps 2026 election","Maximum donation to state legislature Delaware"]', 'Delaware enforces per-election-period contribution limits. An individual may contribute a maximum of $1,200 to a candidate for statewide office, and $600 to a candidate for non-statewide office (such as State Senate or House). Because the primary and general are separate periods, donors can give the maximum for the primary and again for the general.', 'https://elections.delaware.gov/candidates/campaignfinance/pdfs/contributiontable.pdf', 'Delaware Department of Elections - Contribution Table', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('de5dec1bc8eaafd4', 'DE', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Delaware campaigns?', '["Corporate contribution ban Delaware state","Can a business donate to my campaign in DE?","Corporate campaign finance rules Delaware"]', 'Yes. Direct contributions from the general treasury of a corporation, LLC, or labor union to a candidate''s campaign committee are permitted in Delaware. They are subject to the exact same contribution limits as individual donors ($1,200 statewide, $600 non-statewide).', 'https://elections.delaware.gov/candidates/campaignfinance/pdfs/contributiontable.pdf', 'Delaware Department of Elections - Contribution Limits', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('501a32568dd0ec18', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Delaware candidates?', '["DE CFRS filing dates 2026","When are campaign finance reports due in DE?","Delaware pre-primary and pre-general report deadlines"]', 'Delaware requires an annual Year-End report due by December 31. During an election year in which the candidate is on the ballot, the committee must also file a 30-Day Pre-Election Report and an 8-Day Pre-Election Report. (Pending legislation aimed at implementing quarterly reporting takes effect in 2028).', 'https://delcode.delaware.gov/title15/c080/sc02/index.html', 'Delaware Code Title 15 § 8011', '2026-05-17', 'per_cycle', 'statute_citation', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('cf544a1ec27b804a', 'DE', '["state"]', 'finance_ethics', 'Does Delaware provide public financing for state campaigns?', '["Public matching funds for Delaware Governor","State funded campaigns Delaware status","Government campaign grants DE"]', 'No. Delaware does not have a system of public financing or matching funds for state-level political campaigns. Candidates must rely entirely on private contributions raised within the statutory limits.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('7ac4ee687e4966c3', 'DE', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Delaware?', '["DE personal use prohibition campaign finance","Can I use campaign money for personal items in DE?","Prohibited expenditures Delaware CFRS"]', 'Yes. Under Delaware campaign finance laws, campaign funds cannot be converted to personal use. All expenditures must be reasonably related to the election campaign or the execution of the duties of public office.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('e70a139aec1d4c46', 'DE', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Delaware?', '["Delaware candidate personal loan limits","Can I pay myself back for a campaign loan in DE?","Reporting candidate loans in CFRS"]', 'No. A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee; these funds are exempt from standard contribution limits. Loans must be properly documented on disclosures and may be repaid from campaign contributions raised during the cycle.', 'https://www.bolderadvocacy.org/wp-content/uploads/2018/08/Delaware-Campaign-Finance.pdf', 'Delaware Campaign Finance Rules', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('14c94c65885818bb', 'DE', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Delaware?', '["DE PAC donation limits to candidates 2026","Political committee vs individual contribution limit Delaware","Maximum PAC gift to state legislator DE"]', 'In Delaware, Political Action Committees (PACs) are subject to the EXACT SAME contribution limits as individuals and corporations. For the 2025-2026 cycle, a PAC is capped at donating $1,200 per election period to a candidate for statewide office, and $600 to a legislative candidate.', 'https://elections.delaware.gov/candidates/campaignfinance/pdfs/contributiontable.pdf', 'Delaware Department of Elections - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('29e0c2b82ce6ba34', 'DE', '["federal","state"]', 'redistricting', 'Who draws Delaware''s congressional and state legislative maps?', '["Does the DE legislature draw district maps?","Who has the authority to draw district lines in Delaware?","Delaware redistricting commission"]', 'In Delaware, the state legislature (General Assembly) holds the exclusive authority to draw and enact both the single congressional district and the state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_Delaware', 'Ballotpedia - Redistricting in Delaware', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('3ad5588e67eb1e9f', 'DE', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Delaware?', '["Standards for drawing Delaware district lines","Delaware gerrymandering rules","Map requirements DE"]', 'Under the Delaware Constitution and state statutes, districts must be contiguous, be bounded by major roads or natural features when possible, and be as nearly equal in population as possible. They must also not be created to unduly favor any person or political party.', 'https://delcode.delaware.gov/title29/c008/index.html', 'Delaware Code Title 29 § 804', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('c4fab0bc61ee17fc', 'DE', '["state"]', 'redistricting', 'Are the current Delaware state legislative maps operative for the 2026 cycle?', '["Status of Delaware Senate redistricting maps","Are there pending redistricting lawsuits in Delaware?","Delaware 2026 state legislative boundaries"]', 'Yes. The redistricting maps enacted by the Delaware General Assembly following the 2020 census remain fully operative for the 2026 election cycle. There are no ongoing systemic legal challenges preventing their use.', 'https://legis.delaware.gov/', 'Delaware General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('dfff5f4abebbe9f3', 'DE', '["state"]', 'redistricting', 'Does Delaware''s constitutional amendment process affect the creation of an independent redistricting commission?', '["Can Delaware create an independent redistricting commission by ballot measure?","Constitutional barriers to redistricting reform in DE","How to change redistricting rules in Delaware"]', 'Yes, heavily. Because Delaware is the only state where the constitution is amended strictly by a two-thirds vote of the legislature across two successive sessions (without any voter referendum), citizens cannot bypass the legislature to create an independent redistricting commission. The legislature must voluntarily vote to strip itself of mapping power.', 'https://ballotpedia.org/Amending_the_Delaware_Constitution', 'Delaware Constitution', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees and Strategists', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('cf42f593d88fe5f9', 'DE', '["state"]', 'recall_rules', 'Does Delaware have a recall mechanism for state officials?', '["Can the Governor of Delaware be recalled?","How to recall a state senator in DE","Statewide recall election rules Delaware"]', 'No. The State of Delaware does not have any constitutional or statutory provision allowing for the recall of state-level elected officials, including the Governor, statewide executives, or members of the General Assembly.', 'https://ballotpedia.org/Laws_governing_recall_in_Delaware', 'Laws governing recall in Delaware', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('7124163eaa29caae', 'DE', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Delaware?', '["Delaware county council recall rules","Signature requirement local recall Delaware","Recalling a mayor in DE"]', 'There is no statewide, general statutory right to recall local officials in Delaware. Recall is highly restricted and is only permitted in a select few municipalities if their specific, state-approved local city charter explicitly authorizes the recall process.', 'https://ballotpedia.org/Laws_governing_recall_in_Delaware', 'Laws governing recall in Delaware', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('5e3fc4923e37f839', 'DE', '["state"]', 'ballot_access', 'Does Delaware have a citizen initiative process?', '["How to get an initiative on the DE ballot","Delaware citizen initiative signature requirements","Can citizens propose laws in Delaware?"]', 'No. Delaware is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot.', 'https://ballotpedia.org/Initiative_and_referendum_in_Delaware', 'Ballotpedia - Initiative and Referendum in Delaware', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('d27e7ca56fc61816', 'DE', '["state"]', 'ballot_access', 'Does Delaware have a veto referendum process?', '["How to refer a DE bill to the ballot","Delaware citizen referendum rules","Veto referendum signature threshold Delaware state"]', 'No. Delaware does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_Delaware', 'Ballotpedia - Initiative and Referendum in Delaware', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('f3d269a26ab30d08', 'DE', '["state"]', 'ballot_access', 'How does Delaware refer a constitutional amendment to the voters?', '["Legislative referral process Delaware","Referendum by legislature DE","Can the DE legislature put a constitutional amendment on the ballot?"]', 'In the most distinctive constitutional feature in the nation, Delaware NEVER refers constitutional amendments to the voters. Under Article IX of the Delaware Constitution, the General Assembly amends the constitution by securing a two-thirds vote in two consecutive legislative sessions, with an election intervening. Voter ratification is not required.', 'https://delcode.delaware.gov/constitution/constitution.html', 'Delaware Constitution Article IX', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('b95921b7a99ae0e9', 'DE', '["state"]', 'candidate_eligibility', 'Is there an elected Comptroller in Delaware?', '["Requirements to run for DE Comptroller","Who can run for Comptroller in DE?","Delaware Comptroller qualifications"]', 'No. Delaware does not have the office of an elected Comptroller. The state''s financial administration and oversight are divided between the elected State Treasurer and the elected Auditor of Accounts.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('6fa226c64e23f547', 'DE', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for State Treasurer in Delaware?', '["Qualifications for Delaware State Treasurer","Running for Treasurer in DE","Who elects the State Treasurer in Delaware?"]', 'The Delaware State Treasurer is elected by the voters statewide. There are no specific enumerated constitutional age or residency requirements beyond being a qualified elector (registered voter) and citizen of Delaware.', 'https://ballotpedia.org/Delaware_Treasurer', 'Ballotpedia - Delaware Treasurer', '2026-05-17', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8d84ea038570778d', 'DE', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Auditor of Accounts in Delaware?', '["Qualifications for Delaware State Auditor","Running for Auditor in DE","Who elects the Auditor in Delaware?"]', 'The Delaware Auditor of Accounts is a constitutional executive office elected statewide for a four-year term. Similar to the Treasurer, there are no specific constitutional qualifications (such as holding a CPA license) required to run for the office beyond being a qualified elector of the state.', 'https://ballotpedia.org/Delaware_State_Auditor', 'Ballotpedia - Delaware State Auditor', '2026-05-17', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('10699b1029b92b57', 'DE', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Delaware?', '["Run for school board Delaware requirements","Who can be a school board member in DE?","School board residency rules Delaware"]', 'To run for a local school board in Delaware, a candidate must be a citizen of the state and a resident of the specific school district they seek to represent. Candidates who are registered sex offenders or who have been convicted of certain disqualifying felonies are ineligible.', 'https://elections.delaware.gov/school/index.shtml', 'Delaware Department of Elections - School Boards', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('3c593235b7f0b2f4', 'DE', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for justices of the Delaware Supreme Court?', '["Delaware Supreme Court Justice eligibility","Years of practice required for DE Supreme Court","Are Delaware high court judges elected or appointed?"]', 'Delaware Supreme Court justices are NOT elected. They are appointed by the Governor and confirmed by the State Senate for 12-year terms. They must be citizens of the state and learned in the law. Uniquely, the Delaware Constitution dictates strict political balance on the courts (no more than a bare majority may be from the same political party).', 'https://courts.delaware.gov/supreme/', 'Delaware Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('432cd82065712355', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Delaware?', '["How to fix a rejected signature in DE","Delaware ballot cure process deadline","Missing signature on DE mail ballot"]', 'Delaware historically lacked an absentee ballot cure process. However, recent legislative updates (codified via SB 266 in 2026) formally require the Department of Elections to notify voters of certain deficiencies (like a missing signature) on their ballot envelope and offer the voter an opportunity to cure the error before the polls close on Election Day.', 'https://legis.delaware.gov/BillDetail/143031', 'Delaware General Assembly (SB 266)', '2026-05-17', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('d41d72b7ebf601ce', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Delaware?', '["When are military ballots due in Delaware?","UOCAVA return deadline DE","Overseas voting rules Delaware state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. In Delaware, voted UOCAVA absentee ballots must be received by the Department of Elections no later than the close of polls (8:00 p.m.) on Election Day to be counted.', 'https://elections.delaware.gov/voter/absentee/uocava.shtml', 'Delaware Department of Elections - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('0a2d991974ab49e2', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Delaware?', '["What is a provisional ballot in DE?","Voting without ID Delaware","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s name is not on the official poll list but they affirm they are registered and eligible to vote in that district. The voter signs an affidavit on the provisional envelope. Delaware county election officials review the voter''s status post-election to determine if the provisional ballot will be tabulated.', 'https://www.vote411.org/delaware', 'VOTE411 - Delaware', '2026-05-17', 'static', 'secondary_source', 'Voters and Poll Watchers', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8fa2defd4c81e0f1', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Delaware have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Delaware DMV?","DE motor voter automatic registration","Do I have to register to vote if I get a DE driver''s license?"]', 'Yes. Delaware implemented Automatic Voter Registration (AVR) in 2021. Eligible individuals conducting business at the Division of Motor Vehicles are automatically registered to vote or have their address updated, unless they actively decline (opt-out) during the transaction.', 'https://elections.delaware.gov/voter/votereg.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8d44279eb4241a46', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Delaware offer Online Voter Registration?', '["Can I register to vote online in DE?","Delaware electronic voter registration","DE ivote online registration portal"]', 'Yes. Eligible Delaware residents with a valid state driver''s license or DMV-issued ID card can register to vote or update their registration securely using the state''s iVote.de.gov online portal.', 'https://ivote.de.gov/VoterView', 'Delaware Department of Elections - iVote', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8555d22ac9216e27', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Delaware maintain its voter registration lists?', '["DE voter list maintenance rules","How are inactive voters handled in Delaware?","Delaware voter roll cleaning process"]', 'Delaware maintains its voter rolls using the Electronic Registration Information Center (ERIC) to track voters who have moved or died. The Department of Elections also utilizes National Change of Address (NCOA) data. Voters who do not respond to address confirmation notices and fail to vote in two consecutive federal general elections are removed from the active registry.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('e2b5a3e2eb8fb777', 'DE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Delaware?', '["When is the last day to mail my ballot in DE?","Delaware mail ballot postmark deadline","What time are ballots due in Delaware?"]', 'Delaware strictly requires that all voted absentee ballots be physically RECEIVED by the county Department of Elections office by the close of polls (8:00 p.m.) on Election Day. Ballots arriving after 8:00 p.m. on Election Day are rejected, regardless of postmark date. They cannot be returned at Early Voting Sites or standard polling places.', 'https://elections.delaware.gov/voter/absentee/pdfs/absentee_ballot_application.pdf', 'Delaware Department of Elections - Absentee Application', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('b0436ed731db75b8', 'DE', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Delaware?', '["Does Delaware use ranked choice voting?","RCV status in Delaware 2026","Instant runoff voting DE"]', 'No. Ranked Choice Voting (RCV) is not used for any state, federal, or widespread local elections in Delaware. The state relies strictly on the traditional primary and plurality general election system.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('dbc39cdcececb491', 'DE', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Delaware elections?', '["How are tied elections decided in Delaware?","Tie-breaker rules Delaware elections","What happens if a race is tied in DE?"]', 'In the highly unusual event of an exact tie in a general election for a county or statewide office, the Superior Court, sitting as the board of canvass, certifies the tie to the Governor. The Governor is then required to call a special election to resolve the tie.', 'https://codes.findlaw.com/de/title-9-counties/de-code-sect-9-331/', 'Delaware Code Title 9 § 331', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('e9248ba59efb732d', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Delaware campaign materials?', '["Delaware ''Paid for by'' rules","Campaign ad disclaimer requirements DE","Political taglines Delaware CFRS"]', 'Delaware campaign finance law requires that all printed political materials and broadcast advertisements clearly indicate the individual or committee responsible for funding the communication. The disclaimer must clearly state ''Paid for by'' followed by the name of the candidate committee or PAC.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('5d030828f882a75c', 'DE', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Delaware?', '["DE campaign coordination rules","When is a PAC expenditure not independent in Delaware?","Prohibition on candidate-PAC coordination DE"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their authorized campaign committee. Coordinated expenditures are legally treated as in-kind contributions and are subject to Delaware''s strict per-election contribution limits.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('470359f9a4adf324', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Delaware?', '["DE CFRS late fee","Penalty for missing a Delaware campaign finance deadline","State Election Commissioner fine for late filing DE"]', 'The State Election Commissioner assesses mandatory administrative penalties for tardy campaign finance reports. The fine is $50 per day for each day the report is late, up to a maximum of 100 days ($5,000). Candidates may be prohibited from running in future elections if fines are unpaid.', 'https://codes.findlaw.com/de/title-15-elections/de-code-sect-15-8044/', 'Delaware Code Title 15 § 8044', '2026-05-17', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('d21e86168e284a6f', 'DE', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Delaware campaign committee terminate?', '["Closing a Delaware campaign committee","CFRS committee termination requirements","Final campaign finance report Delaware"]', 'A candidate committee may formally terminate when it will no longer receive contributions or make expenditures. The committee must achieve a zero cash balance, legally dispose of all surplus funds, and file a formal Final Report marking the campaign account as closed within the CFRS portal.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('d986eaafa78ca686', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Delaware?', '["DE independent expenditure reporting CFRS","Disclosure for DE independent expenditure groups","Reporting thresholds for outside spending Delaware"]', 'Organizations making independent expenditures must file reports with the State Election Commissioner. The reports must be filed within a standard reporting schedule, except that any independent expenditure exceeding $250 made within 9 days of an election triggers a mandatory 24-hour rapid disclosure report.', 'https://www.ncsl.org/elections-and-campaigns/registration-and-reporting-processes', 'NCSL / Delaware Department of Elections', '2026-05-17', 'static', 'secondary_source', 'Independent groups and PACs', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('a13baa82308054fa', 'DE', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Delaware?', '["Delaware in-kind contribution valuation rules","Reporting non-monetary donations Delaware campaign","Fair market value for in-kind gifts DE"]', 'In-kind contributions (donated goods, services, or equipment not available to the general public) must be reported on CFRS disclosures at their fair market value. They count directly toward the donor''s per-election period contribution limit ($1,200 or $600).', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8995db9ee91780cb', 'DE', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Delaware legislators?', '["Can Delaware legislators raise money during session?","Lobbyist contribution ban DE legislature","Legislative session contribution rules Delaware"]', 'No. Unlike some other states, Delaware does not have a statutory ''session freeze'' that prohibits legislators or statewide officials from accepting campaign contributions while the General Assembly is in regular session.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('a53c42702b5e629f', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What can Delaware candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in DE?","DE surplus campaign funds rules","Donating remaining campaign funds Delaware"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, transfer them to a recognized political party, or donate them to an IRS-recognized tax-exempt charitable organization.', 'https://elections.delaware.gov/candidates/campaignfinance/index.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('a4b48df6f21ebf0d', 'DE', '["state","county","municipal"]', 'finance_ethics', 'What are Delaware''s rapid disclosure requirements for late contributions?', '["Delaware 24-hour large contribution report","Late contribution reporting Delaware CFRS","When do I file a rapid report in DE?"]', 'Third-party groups making independent expenditures must file a 24-hour rapid disclosure report if they make an expenditure exceeding $250 within 9 days of the election, or if they receive a single contribution over $2,000 at any time. Candidates generally adhere to the strict 8-Day Pre-Election report.', 'https://www.ncsl.org/elections-and-campaigns/registration-and-reporting-processes', 'NCSL - Reporting Processes', '2026-05-17', 'static', 'secondary_source', 'All candidates and treasurers', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('db13a075bf48879b', 'DE', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Delaware?', '["When are county sheriffs elected in DE?","Delaware county official term lengths","Are county councils on the 2026 ballot?"]', 'Elected county officials across Delaware''s three counties—including County Executives, Councilmembers, Levy Court Commissioners, and Sheriffs—generally serve four-year staggered terms. Because they are aligned with the presidential and midterm cycles, numerous county offices will be featured on the 2026 ballot.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('f016ad9b92589d1a', 'DE', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Delaware elections?', '["When are Delaware election results official?","DE certification deadline","Superior Court Board of Canvass meeting Delaware"]', 'In Delaware, the Superior Court in each county sits as the Board of Canvass. They convene publicly on the Thursday following the Tuesday election (2 days later) to officially calculate the votes, resolve disputes, and certify the name of the winning candidates, forwarding the results to the Governor.', 'https://law.justia.com/codes/delaware/title-15/chapter-31/subchapter-iv/section-3172/', 'Delaware Code Title 15 § 3172', '2026-05-17', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('9708d63455eef1c1', 'DE', '["federal","state"]', 'election_dates', 'When and how are special elections called in Delaware?', '["Delaware special election timeline","Who calls a special election to fill a US House vacancy in DE?","Filling a midterm vacancy Delaware"]', 'Special elections to fill vacancies in the General Assembly or federal offices are called by a Writ of Election issued by the presiding officer of the respective chamber or the Governor. The Department of Elections then administers the special election within a statutorily defined window.', 'https://elections.delaware.gov/', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('352cb7e9cc00a852', 'DE', '["state"]', 'election_dates', 'What is the role of the State Election Commissioner in Delaware?', '["Who oversees elections in DE?","Delaware Department of Elections structure","State Election Commissioner duties Delaware"]', 'The State Election Commissioner is appointed by the Governor and confirmed by the Senate. They oversee the Department of Elections, ensure uniformity in the administration of election laws across all three counties, manage the state voter registration database, and enforce campaign finance regulations.', 'https://elections.delaware.gov/aboutagency.shtml', 'Delaware Department of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-06-34_delaware_full_v1'),
  ('8a2dbbe9cc05cdd3', 'DE', '["federal","state","county","municipal"]', 'election_dates', 'What are the specific dates for early in-person voting in Delaware for 2026?', '["When is early voting for the Delaware primary 2026?","DE early voting dates 2026 general election","How many days of early voting in Delaware?"]', 'For the 2026 cycle, early voting for the primary election is tentatively scheduled from September 2 to September 13 (with no voting on Labor Day, Sept 6-7). For the November 3 general election, early voting is scheduled from October 22 to November 1 (with polls closed on Oct 25). Polls are open daily during these windows.', 'https://elections.delaware.gov/elections/votinglocations.shtml', 'Delaware Department of Elections - Early Voting Sites', '2026-05-17', 'per_cycle', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-06-34_delaware_full_v1')
